customCss:
/* ===== CELEBRATION FULL-WIDTH BREAKOUT ===== */
/* Make form container full width */
.mfp-pure-grid,.mf-form-wrapper,.mf-form-inner,.mf-form-container,
.mf-form-page,.mf-view-wrap,.mf-view-inner,.mf-embed-wrapper,
form.mf-form, .mf-form {
  max-width: 100% !important;
  width: 100% !important;
  padding-left: 0 !important;
  padding-right: 0 !important;
  margin-left: 0 !important;
  margin-right: 0 !important;
}
/* Celebration wrapper: full viewport width breakout */
.cel-outer {
  width: 100vw !important;
  max-width: 100vw !important;
  position: relative !important;
  left: 50% !important;
  right: 50% !important;
  margin-left: -50vw !important;
  margin-right: -50vw !important;
  box-sizing: border-box !important;
}
.min-h-screen.bg-background.transition-colors {
  width: 100% !important;
}
